body.script:
// ─── JSON-RPC helper ───────────────────────────────────────
async function jsonRpc(url, params) {
    const resp = await fetch(url, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        credentials: 'same-origin',
        body: JSON.stringify({
            jsonrpc: '2.0',
            method: 'call',
            params: params || {},
        }),
    });
    const data = await resp.json();
    if (data.error) {
        throw new Error(data.error.message || data.error.data?.message || 'RPC Error');
    }
    return data.result;
}

// ─── State ──────────────────────────────────────────────────
const state = {
    products: [], allProducts: [], warehouses: [],
    selectedWarehouseId: '', orderLines: [],
    employees: [], selectedEmployeeId: null, selectedEmployeeName: '',
    sessionInfoLoaded: false, defaultWarehouseId: null, defaultPricelistId: null,
    lastOrderId: null, lastOrderData: null,
    returnOrderId: null, returnLines: [],
};

// ─── Init ──────────────────────────────────────────────────
async function initPos() {
    await loadSessionInfo();
    if (!state.selectedEmployeeId) {
        document.getElementById('empScreen').classList.remove('pos-hide');
        document.getElementById('posTerminal').classList.add('pos-hide');
        renderEmployees();
    } else {
        startTerminal();
    }
}

// ─── Session Info ──────────────────────────────────────────
async function loadSessionInfo() {
    try {
        const data = await jsonRpc('/pos_lite/api/session_info', {
            session_id: CURRENT_SESSION_ID || null,
        });
        if (data.success) {
            state.employees = data.employees || [];
            state.defaultWarehouseId = data.default_warehouse_id;
            state.defaultPricelistId = data.default_pricelist_id;
            state.sessionInfoLoaded = true;
            const si = document.getElementById('sessionInfo');
            if (si) si.textContent = 'Session: #' + (CURRENT_SESSION_ID || 'N/A') + ' | พนักงาน ' + state.employees.length + ' คน';
        }
    } catch (e) { console.error('Session info error', e); }
}

// ─── Employee Selection ────────────────────────────────────
function renderEmployees() {
    const grid = document.getElementById('empGrid');
    if (!state.employees.length) {
        grid.innerHTML = '<div style="color:rgba(255,255,255,0.6);grid-column:1/-1;">ไม่พบพนักงานใน session นี้</div>';
        return;
    }
    let html = '';
    state.employees.forEach(function(emp, idx) {
        const initial = (emp.name || '?').charAt(0).toUpperCase();
        html += '<div class="emp-card" data-emp-idx="' + idx + '">'
            + '<div class="emp-avatar">' + initial + '</div>'
            + '<div class="emp-name">' + escapeHtml(emp.name) + '</div>'
            + '<div class="emp-sub">พนักงานขาย</div></div>';
    });
    grid.innerHTML = html;
    grid.querySelectorAll('.emp-card').forEach(function(card) {
        card.addEventListener('click', function() {
            const idx = parseInt(this.getAttribute('data-emp-idx'));
            const emp = state.employees[idx];
            if (emp) selectEmployee(emp.id, emp.name);
        });
    });
}

function selectEmployee(empId, empName) {
    state.selectedEmployeeId = empId;
    state.selectedEmployeeName = empName;
    document.getElementById('empScreen').classList.add('pos-hide');
    document.getElementById('posTerminal').classList.remove('pos-hide');
    document.getElementById('posEmployeeName').textContent = '👤 ' + empName;
    startTerminal();
}

function showEmployeeSwitch() {
    const list = document.getElementById('empSwitchList');
    let html = '';
    state.employees.forEach(function(emp, idx) {
        const active = emp.id === state.selectedEmployeeId ? ' style="background:var(--primary-light);border-color:var(--primary);"' : '';
        html += '<div class="emp-card" data-switch-idx="' + idx + '"' + active + '>'
            + '<div class="emp-name" style="color:var(--text)">' + escapeHtml(emp.name) + '</div></div>';
    });
    list.innerHTML = html;
    list.querySelectorAll('.emp-card').forEach(function(card) {
        card.addEventListener('click', function() {
            const idx = parseInt(this.getAttribute('data-switch-idx'));
            const emp = state.employees[idx];
            if (emp) switchEmployee(emp.id, emp.name);
        });
    });
    document.getElementById('posEmpSwitchModal').classList.add('open');
}

function switchEmployee(empId, empName) {
    state.selectedEmployeeId = empId;
    state.selectedEmployeeName = empName;
    document.getElementById('posEmployeeName').textContent = '👤 ' + empName;
    closeEmployeeSwitch();
}
function closeEmployeeSwitch() { document.getElementById('posEmpSwitchModal').classList.remove('open'); }

// ─── Terminal Start ────────────────────────────────────────
async function startTerminal() { await loadWarehouses(); }

async function loadWarehouses() {
    try {
        const data = await jsonRpc('/pos_lite/api/warehouses', {});
        if (data.success) {
            state.warehouses = data.warehouses;
            const sel = document.getElementById('posWarehouse');
            let html = '';
            data.warehouses.forEach(w => {
                html += '<option value="' + w.id + '">' + escapeHtml(w.name) + ' (' + escapeHtml(w.code || '') + ')</option>';
            });
            sel.innerHTML = html;
            let defaultId = state.defaultWarehouseId;
            if (defaultId && data.warehouses.some(w => w.id == defaultId)) {
                sel.value = defaultId;
            } else if (data.warehouses.length > 0) {
                sel.value = data.warehouses[0].id;
                defaultId = data.warehouses[0].id;
            }
            if (defaultId) { state.selectedWarehouseId = defaultId; await loadProducts(defaultId); }
        }
    } catch (e) { showToast('โหลดคลังสินค้าไม่สำเร็จ', 'error'); }
}

function selectWarehouse(whId) {
    state.selectedWarehouseId = whId; state.orderLines = [];
    renderOrder(); updateTotals(); loadProducts(whId);
}

async function loadProducts(warehouseId) {
    try {
        const data = await jsonRpc('/pos_lite/api/products', {
            session_id: CURRENT_SESSION_ID || null, warehouse_id: warehouseId || null,
        });
        if (data.success) { state.allProducts = data.products; state.products = data.products; filterProducts(); }
    } catch (e) { showToast('โหลดสินค้าไม่สำเร็จ', 'error'); }
}

function filterProducts() {
    const term = document.getElementById('posSearch').value.toLowerCase().trim();
    let filtered = state.allProducts;
    if (term) filtered = filtered.filter(p => (p.name && p.name.toLowerCase().includes(term)) || (p.default_code && p.default_code.toLowerCase().includes(term)) || (p.barcode && p.barcode.toLowerCase().includes(term)));
    state.products = filtered;
    renderProducts();
}

function renderProducts() {
    const el = document.getElementById('posProducts');
    if (!state.products.length) { el.innerHTML = '<div class="pos-no-products"><svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>ไม่พบสินค้า</div>'; return; }
    let html = '';
    state.products.forEach(function(p, idx) {
        const price = typeof p.list_price === 'number' ? p.list_price.toFixed(2) : '0.00';
        const qty = typeof p.qty_available === 'number' ? p.qty_available : 0;
        const outOfStock = qty <= 0;
        const imageHtml = p.image_256 ? '<img class="pos-product-img" src="data:image/png;base64,' + p.image_256 + '" alt="' + escapeHtml(p.name) + '"/>' : '<div class="pos-product-img-placeholder">📦</div>';
        let badge = outOfStock ? '<span class="pos-stock-badge out-of-stock">❌ หมด</span>' : (qty < 5 ? '<span class="pos-stock-badge low-stock">⚠️ ' + qty + '</span>' : '<span class="pos-stock-badge in-stock">✅ ' + qty + '</span>');
        const cardClass = outOfStock ? 'pos-product-card out-of-stock' : 'pos-product-card';
        const dataAttr = outOfStock ? '' : ' data-prod-idx="' + idx + '"';
        html += '<div class="' + cardClass + '"' + dataAttr + '>' + imageHtml
            + '<div class="pos-product-info"><div class="pos-product-name">' + escapeHtml(p.name) + '</div>'
            + (p.default_code ? '<div class="pos-product-code">' + escapeHtml(p.default_code) + '</div>' : '')
            + '<div class="pos-product-price">฿' + price + '</div>' + badge + '</div></div>';
    });
    el.innerHTML = html;
    el.querySelectorAll('.pos-product-card[data-prod-idx]').forEach(function(card) {
        card.addEventListener('click', function() {
            const idx = parseInt(this.getAttribute('data-prod-idx'));
            const p = state.products[idx];
            if (p) addProduct(p.id, p.name, p.list_price, p.default_code || '');
        });
    });
}

function addProduct(id, name, price, code) {
    const prod = state.allProducts.find(p => p.id === id);
    const qtyAvailable = prod && typeof prod.qty_available === 'number' ? prod.qty_available : 0;
    const existing = state.orderLines.find(l => l.productId === id);
    const currentQty = existing ? existing.qty : 0;
    if (currentQty >= qtyAvailable) { showToast('สินค้าหมด: ' + name, 'error'); return; }
    const image = prod && prod.image_128 ? prod.image_128 : null;
    if (existing) { existing.qty += 1; }
    else { state.orderLines.push({ productId: id, name, price, code: code || '', qty: 1, discount: 0, image: image, tax_rate: prod && typeof prod.tax_rate === 'number' ? prod.tax_rate : 0 }); }
    renderOrder(); updateTotals();
}

function changeQty(id, delta) {
    const line = state.orderLines.find(l => l.productId === id);
    if (!line) return;
    if (delta > 0) {
        const prod = state.allProducts.find(p => p.id === id);
        if (line.qty >= (prod && typeof prod.qty_available === 'number' ? prod.qty_available : 0)) { showToast('สินค้าหมด: ' + line.name, 'error'); return; }
    }
    line.qty += delta;
    if (line.qty <= 0) state.orderLines = state.orderLines.filter(l => l.productId !== id);
    renderOrder(); updateTotals();
}
function removeLine(id) { state.orderLines = state.orderLines.filter(l => l.productId !== id); renderOrder(); updateTotals(); }
function setDiscount(id, val) { const line = state.orderLines.find(l => l.productId === id); if (line) { line.discount = Math.max(parseFloat(val) || 0, 0); renderOrder(); updateTotals(); } }

function renderOrder() {
    const el = document.getElementById('posOrderLines');
    if (!state.orderLines.length) { el.innerHTML = '<div class="pos-empty-cart"><svg width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><circle cx="9" cy="21" r="1"/><circle cx="20" cy="21" r="1"/><path d="M1 1h4l2.68 13.39a2 2 0 0 0 2 1.61h9.72a2 2 0 0 0 2-1.61L23 6H6"/></svg>ยังไม่มีรายการ</div>'; return; }
    let html = '';
    state.orderLines.forEach(l => {
        const subtotal = (l.price * l.qty).toFixed(2);
        const imgHtml = l.image ? '<img class="pos-order-line-img" src="data:image/png;base64,' + l.image + '"/>' : '<div class="pos-order-line-img-placeholder">📦</div>';
        const discVal = l.discount || 0;
        const lineTotal = discVal > 0 ? ((l.price - discVal) * l.qty).toFixed(2) : subtotal;
        html += '<div class="pos-order-line">' + imgHtml
            + '<div class="pos-order-line-info"><div class="pos-order-line-name">' + escapeHtml(l.name) + '</div>'
            + '<div class="pos-order-line-qty-controls">'
            + '<button onclick="changeQty(' + l.productId + ', -1)"><svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/></svg></button>'
            + '<span class="qty">' + l.qty + '</span>'
            + '<button onclick="changeQty(' + l.productId + ', 1)"><svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg></button>'
            + '</div></div>'
            + '<div class="pos-order-line-disc"><input type="number" min="0" step="0.01" value="' + discVal + '" onchange="setDiscount(' + l.productId + ', this.value)" /><span>฿</span></div>'
            + '<div class="pos-order-line-price">฿' + lineTotal + '</div>'
            + '<button class="pos-order-line-remove" onclick="removeLine(' + l.productId + ')"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3 6 5 6 21 6"/><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a4 4 0 0 1 4-4h4a4 4 0 0 1 4 4v2"/></svg></button></div>';
    });
    el.innerHTML = html;
}

function updateTotals() {
    let subtotal = 0, tax = 0;
    state.orderLines.forEach(l => { const disc = l.discount || 0; const base = Math.max(l.price - disc, 0) * l.qty; subtotal += base; tax += base * (l.tax_rate || 0) / 100; });
    subtotal = Math.round(subtotal * 100) / 100;
    tax = Math.round(tax * 100) / 100;
    const total = Math.round((subtotal + tax) * 100) / 100;
    document.getElementById('posSubtotal').textContent = '฿' + subtotal.toFixed(2);
    document.getElementById('posTax').textContent = '฿' + tax.toFixed(2);
    document.getElementById('posTotal').textContent = '฿' + total.toFixed(2);
    const btn = document.getElementById('posPayBtn');
    if (state.orderLines.length > 0) { btn.disabled = false; btn.textContent = 'ดำเนินการ ฿' + total.toFixed(2); }
    else { btn.disabled = true; btn.textContent = 'ดำเนินการ ฿0.00'; }
}

// ─── Process ───────────────────────────────────────────────
function openProcessModal() {
    let base = 0, taxAmt = 0;
    state.orderLines.forEach(l => { const disc = l.discount || 0; const lineBase = Math.max(l.price - disc, 0) * l.qty; base += lineBase; taxAmt += lineBase * (l.tax_rate || 0) / 100; });
    const withTax = Math.round((base + taxAmt) * 100) / 100;
    document.getElementById('modalTotal').textContent = '฿' + withTax.toFixed(2);
    document.getElementById('posProcessModal').classList.add('open');
}
function closeProcessModal() { document.getElementById('posProcessModal').classList.remove('open'); }

async function confirmProcess() {
    const params = {
        customer_name: document.getElementById('custName').value,
        partner_phone: document.getElementById('custPhone').value,
        partner_address: document.getElementById('custAddress').value,
        channel: 'walkin',
        session_id: CURRENT_SESSION_ID || null,
        employee_id: state.selectedEmployeeId,
        warehouse_id: parseInt(state.selectedWarehouseId) || null,
        line_ids: state.orderLines.map(l => [0, 0, { product_id: l.productId, qty: l.qty, price_unit: l.price, discount: l.discount || 0, discount_type: 'fixed' }]),
    };

    try {
        const data = await jsonRpc('/pos_lite/api/create_order', params);
        if (data.success) {
            state.lastOrderId = data.order_id;
            // Load order detail for print modal
            loadAndShowPrintDetail(data.order_id, data.name);
            state.orderLines = []; renderOrder(); updateTotals(); closeProcessModal();
        } else { showToast('เกิดข้อผิดพลาด: ' + (data.error || 'ไม่ทราบสาเหตุ'), 'error'); }
    } catch (e) { showToast('ไม่สามารถสร้างออเดอร์ได้', 'error'); }
}

// ─── Print Detail ──────────────────────────────────────────
async function loadAndShowPrintDetail(orderId, orderName) {
    try {
        const data = await jsonRpc('/pos_lite/api/order_detail', { order_id: orderId });
        if (data.success) {
            state.lastOrderData = data.order;
            renderPrintDetail();
        } else {
            showSimplePrintDetail(orderName);
        }
    } catch (e) {
        showSimplePrintDetail(orderName);
    }
    document.getElementById('posPrintDetailModal').classList.add('open');
}

function renderPrintDetail() {
    const o = state.lastOrderData;
    if (!o) return;
    document.getElementById('printOrderName').textContent = o.name;
    document.getElementById('printOrderDate').textContent = o.date_order ? new Date(o.date_order).toLocaleString('th-TH') : '';

    // Summary
    let html = '<div class="pos-print-summary">';
    html += '<div class="pos-print-summary-row label"><span>รายการ</span><span>รวม</span></div>';
    o.lines.forEach(l => {
        html += '<div class="pos-print-summary-row"><span>' + escapeHtml(l.product_name) + ' × ' + l.qty + '</span><span>฿' + Number(l.price_total).toFixed(2) + '</span></div>';
    });
    html += '<div class="pos-print-summary-row total"><span>รวมสุทธิ</span><span>฿' + Number(o.amount_total).toFixed(2) + '</span></div>';
    html += '</div>';
    document.getElementById('printOrderSummary').innerHTML = html;

    // Invoice button
    const invBtn = document.getElementById('printInvoiceBtn');
    if (o.print_urls && o.print_urls.invoice) {
        invBtn.style.display = 'block';
        invBtn.setAttribute('data-url', o.print_urls.invoice);
    } else {
        invBtn.style.display = 'none';
    }

    // Store print URLs
    if (o.print_urls) {
        state.lastOrderData._printUrls = o.print_urls;
    }
}

function showSimplePrintDetail(orderName) {
    document.getElementById('printOrderName').textContent = orderName;
    document.getElementById('printOrderDate').textContent = '';
    document.getElementById('printOrderSummary').innerHTML = '';
}

function printReceipt(size) {
    const o = state.lastOrderData;
    if (!o || !o._printUrls) return;
    const url = o._printUrls['receipt_' + size];
    if (url) window.open(url, '_blank');
}

function printInvoice() {
    const btn = document.getElementById('printInvoiceBtn');
    const url = btn.getAttribute('data-url');
    if (url) window.open(url, '_blank');
}

function closePrintDetail() {
    document.getElementById('posPrintDetailModal').classList.remove('open');
}

// ─── History / Return ──────────────────────────────────────
async function showHistoryOrders() {
    document.getElementById('posHistoryModal').classList.add('open');
    document.getElementById('historyOrderList').innerHTML = '<p style="color:var(--text-secondary);font-size:13px;">กำลังโหลด...</p>';
    try {
        const data = await jsonRpc('/pos_lite/api/orders_for_return', { limit: 50 });
        if (data.success) {
            const list = document.getElementById('historyOrderList');
            if (!data.orders.length) {
                list.innerHTML = '<p style="color:var(--text-secondary);font-size:13px;text-align:center;padding:20px 0;">ไม่มีออเดอร์</p>';
                return;
            }
            let html = '';
            data.orders.forEach(function(o, idx) {
                const dateStr = o.date_order ? new Date(o.date_order).toLocaleDateString('th-TH') : '';
                html += '<div class="pos-history-order" data-order-idx="' + idx + '">'
                    + '<div class="ho-info"><div class="ho-name">' + escapeHtml(o.name) + '</div>'
                    + '<div class="ho-meta">' + dateStr + ' · ' + escapeHtml(o.customer_name || 'ลูกค้า') + (o.employee_name ? ' · ' + escapeHtml(o.employee_name) : '') + '</div></div>'
                    + '<div class="ho-amount">฿' + Number(o.amount_total).toFixed(2) + '</div></div>';
            });
            list.innerHTML = html;
            list.querySelectorAll('.pos-history-order').forEach(function(el) {
                el.addEventListener('click', function() {
                    const idx = parseInt(this.getAttribute('data-order-idx'));
                    const o = data.orders[idx];
                    if (o) openReturnWizard(o.id, o.name);
                });
            });
        }
    } catch (e) { showToast('โหลดประวัติไม่สำเร็จ', 'error'); }
}

function closeHistoryOrders() { document.getElementById('posHistoryModal').classList.remove('open'); }

// ─── Return/Exchange Wizard ────────────────────────────────
async function openReturnWizard(orderId, orderName) {
    closeHistoryOrders();
    state.returnOrderId = orderId;
    document.getElementById('returnWizardTitle').textContent = '🔄 คืนสินค้า — ' + orderName;
    document.getElementById('returnWizardBody').innerHTML = '<p style="color:var(--text-secondary);font-size:13px;">กำลังโหลด...</p>';

    try {
        const data = await jsonRpc('/pos_lite/api/order_detail', { order_id: orderId });
        if (data.success) {
            const o = data.order;
            let html = '<div style="margin-bottom:12px;"><div class="pos-section-title">เลือกสินค้าที่ต้องการคืน</div><div id="returnOrderLines">';
            o.lines.forEach(l => {
                html += '<div class="pos-return-line"><label>'
                    + '<input type="checkbox" class="return-checkbox" data-product-id="' + l.product_id + '" data-price="' + l.price_unit + '" data-qty="' + l.qty + '" onchange="calcReturnTotal()"/>'
                    + '<span class="rl-name">' + escapeHtml(l.product_name) + '</span>'
                    + '<span class="rl-qty">× ' + l.qty + '</span>'
                    + '<span class="rl-price">฿' + Number(l.price_unit).toFixed(2) + '</span>'
                    + '</label></div>';
            });
            html += '</div></div>';
            html += '<div class="pos-form-group"><label>เหตุผลการคืน</label><input type="text" id="returnReason" placeholder="ระบุเหตุผล"/></div>';
            html += '<div class="pos-form-group"><label>วิธีการรับเงินคืน</label><select id="returnPaymentMethod" style="width:100%;padding:9px 10px;border:1px solid var(--border);border-radius:8px;font-size:14px;">'
                + '<option value="cash">เงินสด (Cash)</option><option value="transfer">โอน (Transfer)</option><option value="card">บัตรเครดิต (Card)</option></select></div>';
            html += '<div style="margin-top:8px;padding:10px;background:var(--primary-bg);border-radius:8px;"><div style="display:flex;justify-content:space-between;font-size:14px;">'
                + '<span>ยอดคืนสินค้า</span><span id="returnTotalAmount" style="font-weight:700;color:var(--primary);">฿0.00</span></div></div>';
            document.getElementById('returnWizardBody').innerHTML = html;
            document.getElementById('posReturnWizardModal').classList.add('open');
        }
    } catch (e) { showToast('โหลดรายละเอียดออเดอร์ไม่สำเร็จ', 'error'); }
}

function calcReturnTotal() {
    let total = 0;
    document.querySelectorAll('.return-checkbox:checked').forEach(cb => {
        const price = parseFloat(cb.getAttribute('data-price')) || 0;
        const qty = parseFloat(cb.getAttribute('data-qty')) || 1;
        total += price * qty;
    });
    document.getElementById('returnTotalAmount').textContent = '฿' + total.toFixed(2);
}

async function confirmReturn() {
    const checked = document.querySelectorAll('.return-checkbox:checked');
    if (!checked.length) { showToast('กรุณาเลือกสินค้าที่ต้องการคืน', 'warning'); return; }

    let lines = [];
    let total = 0;
    checked.forEach(cb => {
        const productId = parseInt(cb.getAttribute('data-product-id'));
        const price = parseFloat(cb.getAttribute('data-price')) || 0;
        const qty = parseFloat(cb.getAttribute('data-qty')) || 1;
        lines.push({ product_id: productId, qty: qty, price_unit: price });
        total += price * qty;
    });

    const params = {
        original_order_id: state.returnOrderId,
        lines: lines,
        reason: document.getElementById('returnReason').value || '',
        payment_method: document.getElementById('returnPaymentMethod').value || 'cash',
        amount: total,
        session_id: CURRENT_SESSION_ID || null,
        employee_id: state.selectedEmployeeId,
    };

    try {
        const data = await jsonRpc('/pos_lite/api/create_return', params);
        if (data.success) {
            showToast('คืนสินค้าสำเร็จ — ' + data.name, 'success');
            closeReturnWizard();
        } else {
            showToast('เกิดข้อผิดพลาด: ' + (data.error || 'ไม่ทราบสาเหตุ'), 'error');
        }
    } catch (e) { showToast('ไม่สามารถดำเนินการคืนสินค้าได้', 'error'); }
}

function closeReturnWizard() {
    document.getElementById('posReturnWizardModal').classList.remove('open');
    state.returnOrderId = null;
}

// ─── Helpers ────────────────────────────────────────────────
function escapeHtml(s) { if (!s) return ''; return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function escapeJs(s) { if (!s) return ''; return String(s).replace(/\\/g,'\\\\').replace(/'/g,"\\'"); }
function showToast(msg, type) {
    const el = document.getElementById('posToast');
    el.textContent = msg; el.className = 'pos-toast ' + type + ' show';
    if (type !== 'warning') setTimeout(function() { el.classList.remove('show'); }, 3000);
}

// ─── Keyboard ──────────────────────────────────────────────
document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape') { closeProcessModal(); closeEmployeeSwitch(); closePrintDetail(); closeReturnWizard(); closeHistoryOrders(); }
    if (e.ctrlKey && e.key === 'p') { e.preventDefault(); openProcessModal(); }
});

// ─── Bootstrap ──────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', initPos);
